@@ -173,0 +173,28 @@
+
+                    if (decompressedSize == 0) {
+                        if (inflater.needsDictionary()) {
+                            if (SSLLogger.isOn()
+                                    && SSLLogger.isOn(
+                                    SSLLogger.Opt.HANDSHAKE)) {
+                                SSLLogger.warning("Compressed input requires"
+                                        + " a dictionary");
+                            }
+
+                            return null;
+                        }
+
+                        if (inflater.needsInput()) {
+                            if (SSLLogger.isOn()
+                                    && SSLLogger.isOn(
+                                    SSLLogger.Opt.HANDSHAKE)) {
+                                SSLLogger.warning(
+                                        "Incomplete compressed input");
+                            }
+
+                            return null;
+                        }
+
+                        // Else just break the loop.
+                        break;
+                    }
+
